import secureStorage from '../utils/secureStorage';

export const saveUserSession = async (authToken, refreshToken, userProfile) => {
  try {
    await secureStorage.saveAuthToken(authToken);
    await secureStorage.saveRefreshToken(refreshToken);
    await secureStorage.saveUserProfile(userProfile);
    return true;
  } catch (error) {
    console.error('Error saving user session:', error);
    throw error;
  }
};

export const getUserSession = async () => {
  try {
    const authToken = await secureStorage.getAuthToken();
    const refreshToken = await secureStorage.getRefreshToken();
    const userProfile = await secureStorage.getUserProfile();
    
    return {
      authToken,
      refreshToken,
      userProfile
    };
  } catch (error) {
    console.error('Error getting user session:', error);
    return null;
  }
};

export const clearUserSession = async () => {
  try {
    await secureStorage.clearUserData();
    return true;
  } catch (error) {
    console.error('Error clearing user session:', error);
    throw error;
  }
};

